1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_NUMERATOR = 11;
26	const FIRST_INSURANCE_DENOMINATOR = 10;
27	const PROCESSING_FEE = 5;
28	
29	const COMPONENT_PREMIUM = 25;
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	const componentBasePremium = (count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
36	
37	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
38	
39	const componentTotal = (items: Item[]): number => {
40	  const countsByType = new Map<string, number>();
41	  for (const item of items.filter(isComponent)) {
42	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
43	  }
44	  return [...countsByType.values()].reduce(
45	    (sum, count) => sum + componentBasePremium(count),
46	    0,
47	  );
48	};
49	
50	const basePremium = (items: Item[]): number => {
51	  const mainTotal = items
52	    .filter((item) => !isComponent(item))
53	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
54	  return mainTotal + componentTotal(items);
55	};
56	
57	const quotePremium = (items: Item[]): number => {
58	  const base = basePremium(items);
59	  const withFirstInsurance =
60	    (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
61	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
62	};
63	
64	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
65	  const results = scenario.steps.map((step) => ({
66	    premium: quotePremium(step.items),
67	  }));
68	  return { results };
69	};
